// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	if (isLoading || newValue === '') {
		return;
	}

	// STRY0071533 -  https://www.servicenowguru.com/scripting/client-scripts-scripting/client-side-dates-in-servicenow/
	// based on the article referenced above, this should work for the function below.
	// we can use the user's date and time format instead of forcing one.
	if(oldValue == newValue){
		return;
	}

	// noticed that if you click on the suspense date field and off, then you get a date in the format of the user
	// but, if you load, you get the format in the format of the server.
	// when the getDateFromFormat is used with the wrong format it returns zero
	// so, check for zerio and try just getting a date field to use to compare

	var newValueNumer = getDateFromFormat(newValue, g_user_date_time_format);
	// STRY0081525 - now was set as a string before, it may have caused errors in dates in some scenarios before
	var now = new Date().getTime();

	// NOTE: if we add a system setting or a Task setting for no Time, then we would set NOW to be just the date with time 00:00:00.  
	// The Suspense date would also need to chage to g_user_date_format.  But, it can be handled better using the client capabilities

	// STRY0072379
	if(g_scratchpad.suspenseDatesAndExpctedStartDatesMustBeInTheFuture == 'true'){
		// STRY0081525 - isReadOnly does not work on platform, isDisabled does not work on portal
		var suspenseDateReadOnly = ((typeof spModal != 'undefined') 
									? g_form.isReadOnly('suspense_date') == true 
									: g_form.isDisabled('suspense_date') == true);

		if(newValueNumer < now && (suspenseDateReadOnly != true)){
			g_form.clearValue('suspense_date');
			g_form.showFieldMsg('suspense_date','The Suspense Date must be a date in the future.', 'error', true);
			return;
		}
	}
	var toastMsg = '';
	var strSuspenseDate = g_form.getValue('suspense_date');
	var dteSuspenseDate = getDateFromFormat(strSuspenseDate, g_user_date_time_format);
	var strExternalDueDate = g_form.getValue('u_external_due_date');
	var dteExternalDueDate = getDateFromFormat(strExternalDueDate, g_user_date_time_format);
	g_form.hideFieldMsg('suspense_date', true);
	g_form.hideFieldMsg('u_external_due_date', true);
	g_form.clearMessages();

	// STRY0077867
	if(!g_form.getValue('parent')){
		if(g_form.getValue('tasking_authority.u_external_flag') == 'true'){
			// DFCT0011027 - check external date entered and don't show message if blank
			if(dteExternalDueDate > 0 && dteSuspenseDate > dteExternalDueDate){
				g_form.showFieldMsg('suspense_date', getMessage('Suspense Date AFTER External Due Date'), 'error', true);
			}
		} else if(g_form.getValue('outbound') == 'true'){
			// STRY0077947
			if(dteExternalDueDate > dteSuspenseDate){
				g_form.showFieldMsg('u_external_due_date', getMessage('External Due Date is AFTER the Suspense Date'), 'error', true);
			}
		}
	} else if(g_form.getValue('outbound') == 'true'){
		// STRY0077947
		if(dteExternalDueDate > dteSuspenseDate){
			g_form.showFieldMsg('u_external_due_date', getMessage('External Due Date is AFTER the Suspense Date'), 'error', true);
		}
	}

	// v2.5 P2 | 08.24.2020 | STRY0077855 - STRY0077847 : Suspense Date Timing Updates
	var task_id = g_form.getUniqueValue();
//	var taskNewSuspenseDate = g_form.getValue("suspense_date");

	var ajax = new GlideAjax('ClientTaskInfo');
	ajax.addParam('sysparm_name', 'compareTaskSuspenseDateToParentAndChildDates');
	ajax.addParam('sysparm_task_id', g_form.getUniqueValue());
	ajax.addParam('sysparm_parent_task_id', g_form.getValue('parent'));
	// STRY0091972
	ajax.addParam('sysparm_taskNewSuspenseDate', strSuspenseDate);
	ajax.getXML(function(response){
		try{
			var data = response.responseXML.documentElement.getAttribute("answer");
			var checkDates = JSON.parse(data);
			// STRY0077855
			if(checkDates.subtaskSuspenseDateOlderThanParent){
				g_form.showFieldMsg('suspense_date', getMessage('A Subtask has a Suspense Date AFter this Task'), 'error', true);
				if (typeof spModal != 'undefined' ) {
					var linkToPlatform = '../x_153465_discovert_route_task_instance.do?sys_id=' + g_form.getUniqueValue();
					toastMsg = getMessage('Portal Toast A Subtask has a Suspense Date After the Suspense Date on this Task');
					toastMsg = toastMsg.replace('doNotTranslageLinkToPlatform', linkToPlatform);
				}else{
					toastMsg = getMessage('Platform Toast A Subtask has a Suspense Date After the Suspense Date on this Task');
				}
				g_form.addErrorMessage(toastMsg);
			}
			// STRY0077847
			if(checkDates.taskSuspenseDateOlderThanParent){
				g_form.showFieldMsg('suspense_date', getMessage('Subtask Suspense Date AFTER Parent Task Suspense Date'), 'error', true);
			}
		}catch(e){		
			jslog(e);
		}
	});
}
